const data = $input.first().json;

console.log('=== DEBUG KLIENT ===');
console.log('spreadsheetId:', data.spreadsheetId);
console.log('sheetName:', data.sheetName);
console.log('clickupListaId:', data.clickupListaId);
console.log('długość ID:', (data.spreadsheetId || '').length);

// Walidacja
if (!data.spreadsheetId || data.spreadsheetId.length < 10) {
  throw new Error(`Nieprawidłowy spreadsheetId: "${data.spreadsheetId}"`);
}

if (!data.sheetName) {
  throw new Error('Brak sheetName');
}

return [{ json: data }];

const client = $input.first().json;

const isActive = String(client.aktywny || '').toUpperCase().trim();
if (isActive !== 'TRUE' && isActive !== '1' && isActive !== 'TAK') {
  return [{ json: { __skip: true, powod: 'nieaktywny', klient: client.nazwa } }];
}

if (!client.spreadsheet_id || !client.clickup_lista_id) {
  return [{ json: { __skip: true, powod: 'brak spreadsheet_id lub clickup_lista_id', klient: client.nazwa } }];
}

const MONTHS_PL = [
  'STYCZEŃ','LUTY','MARZEC','KWIECIEŃ',
  'MAJ','CZERWIEC','LIPIEC','SIERPIEŃ',
  'WRZESIEŃ','PAŹDZIERNIK','LISTOPAD','GRUDZIEŃ'
];

const now = new Date();
const sheetName = `${MONTHS_PL[now.getMonth()]} CONTENT CALENDAR`;

console.log(`✅ Klient: ${client.nazwa} → ${sheetName}`);

return [{
  json: {
    __skip:         false,
    klientId:       String(client.klient_id || ''),
    klientNazwa:    String(client.nazwa || ''),
    spreadsheetId:  String(client.spreadsheet_id || '').trim(),
    clickupListaId: String(client.clickup_lista_id || '').trim(),
    sheetName
  }
}];

// ============================================
// SPLIT ROWS — parsuj arkusz → osobny item per post
// ============================================

const sheetResp  = $input.first().json;
const clientMeta = $('⚙️ Przygotuj Klienta3').first().json;

console.log('=== SPLIT ROWS START ===');
console.log('clientMeta.klientNazwa:', clientMeta.klientNazwa);
console.log('sheetResp ma values:', !!sheetResp.values);
console.log('sheetResp error:', sheetResp.error || 'brak');

// Sprawdź czy arkusz istnieje
if (sheetResp.error || !sheetResp.values) {
  console.warn(`Brak arkusza dla ${clientMeta.klientNazwa}: ${clientMeta.sheetName}`);
  return [{ json: {
    __noData:    true,
    klientNazwa: clientMeta.klientNazwa,
    sheetName:   clientMeta.sheetName
  }}];
}

const values = sheetResp.values;

// ── Pomocnicze ───────────────────────────────
// UWAGA: numery wierszy jak w Sheets (1-based)
function cell(rowNum, colIdx) {
  const row = values[rowNum - 1] || [];
  return (row[colIdx] || '').toString().trim();
}

// ── Mapowanie wierszy (numery jak w Google Sheets) ──
const R = {
  data:        5,
  tytul:       6,
  typGrafiki:  7,
  typPosta:    8,
  linkGrafiki: 11,
  opis:        13,
  cta:         15,
  hasztagi:    17,
  status:      19,
  notatki:     21,
  feedback:    23,
  taskId:      25
};

// ── Znajdź kolumny z datami ──────────────────
const dateRowArr = values[R.data - 1] || [];
const dataCols   = [];

for (let i = 0; i < dateRowArr.length; i++) {
  const v = (dateRowArr[i] || '').toString().trim();
  if (v.match(/202\d/) && v.length > 5) {
    dataCols.push(i);
  }
}

console.log(`Kolumny z datami: ${dataCols.length}`);
console.log(`Przykład wiersz 5: ${dateRowArr.slice(0,5).join(' | ')}`);

// ── Parsowanie daty PL ───────────────────────
const MO = {
  'stycznia':0,'lutego':1,'marca':2,'kwietnia':3,
  'maja':4,'czerwca':5,'lipca':6,'sierpnia':7,
  'wrzesnia':8,'wrzesień':8,'pazdziernika':9,'października':9,
  'listopada':10,'grudnia':11
};

function parseDate(str) {
  if (!str) return null;
  try {
    const normalized = str
      .toLowerCase()
      .replace(/ą/g,'a').replace(/ę/g,'e')
      .replace(/ó/g,'o').replace(/ś/g,'s')
      .replace(/ł/g,'l').replace(/ż/g,'z')
      .replace(/ź/g,'z').replace(/ć/g,'c')
      .replace(/ń/g,'n');
    const m = normalized.match(/(\d{1,2})\s+(\w+)\s+(\d{4})/);
    if (m) {
      const mon = MO[m[2]] ?? MO[str.toLowerCase().match(/(\d{1,2})\s+(\w+)\s+(\d{4})/)?.[2]];
      if (mon !== undefined) {
        return new Date(parseInt(m[3]), mon, parseInt(m[1]));
      }
    }
  } catch(e) { console.warn('parseDate error:', e.message); }
  return null;
}

// ── Mapowanie statusów ───────────────────────
const SM = {
  'APPROVED':             'Zatwierdzone przez klienta',
  'WAITING FOR APPROVAL': 'Wyslane do klienta',
  'NEEDS EDITING':        'Poprawki zakonczone',
  'NEEDS EDIT':           'Poprawki zakonczone',
  'DRAFT':                'Do zrobienia',
  'IN PROGRESS':          'W realizacji',
  'PUBLISHED':            'W realizacji'
};

function mapStatus(s) {
  if (!s) return 'Do zrobienia';
  return SM[s.toUpperCase().trim()] || 'Do zrobienia';
}

// ── Indeks kolumny → litera ──────────────────
function colToLetter(idx) {
  let r = '', n = idx + 1;
  while (n > 0) {
    n--;
    r = String.fromCharCode(65 + (n % 26)) + r;
    n = Math.floor(n / 26);
  }
  return r;
}

// ── Walidacja task_id ────────────────────────
const PUSTE = new Set([
  '','brak','none','null','undefined',
  'task_id','task id','-','—'
]);

function czyMaTask(id) {
  return id.length > 0 && !PUSTE.has(id.toLowerCase());
}

// ── Buduj posty ──────────────────────────────
const posts = [];

for (const ci of dataCols) {
  const tytul     = cell(R.tytul,  ci);
  const opis      = cell(R.opis,   ci);
  const statusRaw = cell(R.status, ci);
  const taskId    = cell(R.taskId, ci).trim();

  if (!tytul && !opis) continue;
  if (!statusRaw)      continue;

  const dataRaw    = cell(R.data,        ci);
  const typGrafiki = cell(R.typGrafiki,  ci);
  const typPosta   = cell(R.typPosta,    ci) || 'Post';
  const rawLink    = cell(R.linkGrafiki, ci);
  const cta        = cell(R.cta,        ci);
  const hasztagi   = cell(R.hasztagi,   ci);
  const notatki    = cell(R.notatki,    ci);
  const feedback   = cell(R.feedback,   ci);

  const cleanLink  = rawLink.toLowerCase().includes('link to google') ? '' : rawLink;
  const dateObj    = parseDate(dataRaw);
  const colLetter  = colToLetter(ci);
  const juzMaTask  = czyMaTask(taskId);

  console.log(`  Kolumna ${colLetter}: "${tytul}" | status: ${statusRaw} | taskId: "${taskId}" | juzMaTask: ${juzMaTask}`);

  posts.push({
    klientId:       clientMeta.klientId,
    klientNazwa:    clientMeta.klientNazwa,
    clickupListaId: clientMeta.clickupListaId,
    spreadsheetId:  clientMeta.spreadsheetId,
    sheetName:      clientMeta.sheetName,

    colIdx:         ci,
    colLetter,
    writeRange:     `${clientMeta.sheetName}!${colLetter}25`,

    dataRaw,
    postDateISO:    dateObj ? dateObj.toISOString() : null,
    postDateLabel:  dateObj
      ? dateObj.toLocaleDateString('pl-PL',{
          weekday:'long', day:'numeric',
          month:'long',   year:'numeric'
        })
      : dataRaw,
    dueTimestamp: dateObj ? dateObj.getTime() : null,

    tytul, typGrafiki, typPosta,
    linkGrafiki: cleanLink,
    opis, cta, hasztagi,

    statusRaw,
    clickupStatus: mapStatus(statusRaw),

    taskId,
    juzMaTask,

    notatki,
    feedback,

    __noData: false
  });
}

console.log(`\n📊 ${clientMeta.klientNazwa}: ${posts.length} postów`);
console.log(`  Nowe:          ${posts.filter(p => !p.juzMaTask).length}`);
console.log(`  Aktualizacje:  ${posts.filter(p =>  p.juzMaTask).length}`);

if (posts.length === 0) {
  return [{ json: { __noData: true, klientNazwa: clientMeta.klientNazwa } }];
}

return posts.map(p => ({ json: p }));

