// Tryb: runOnceForEachItem
const newTask  = item.json;

// W runOnceForEachItem, $itemIndex = index aktualnego itemu
// Pobierz odpowiadający post z Split Rows3 po indeksie
const allPosts = $('✂️ Split Rows3').all();
const postData = allPosts[$itemIndex]?.json;

if (!postData) {
  throw new Error(`Brak postData dla item index ${$itemIndex}. Mam ${allPosts.length} postów.`);
}

if (!newTask.id) {
  throw new Error(`Brak ID taska dla: ${postData.tytul} — response: ${JSON.stringify(newTask).slice(0,300)}`);
}

const colLetter  = postData.colLetter;
const TASKID_ROW = 25;
const sheetName  = postData.sheetName;

if (!colLetter) {
  throw new Error(`Brak colLetter dla "${postData.tytul}"`);
}

// BEZ APOSTROFÓW — encodeURIComponent załatwi polskie znaki
const writeRange = `${sheetName}!${colLetter}${TASKID_ROW}`;

console.log(`✅ [${$itemIndex}] Task ${newTask.id} → ${writeRange} (${postData.tytul})`);

return {
  json: {
    newTaskId:     newTask.id,
    writeRange,
    spreadsheetId: postData.spreadsheetId,
    sheetName,
    klientNazwa:   postData.klientNazwa,
    tytul:         postData.tytul,
    colLetter
  }
};

const d = $input.first().json;
console.log(`⏭️ Następny klient po: ${d.klientNazwa || d.tytul || 'nieznany'}`);
return [{ json: d }];

// ==================== HELPERS ====================

function colIndexToLetter(index) {
  let letter = '';
  let n = index;
  while (n >= 0) {
    letter = String.fromCharCode((n % 26) + 65) + letter;
    n = Math.floor(n / 26) - 1;
  }
  return letter;
}

function parseDateToTimestamp(dateStr) {
  if (!dateStr) return null;
  const s = String(dateStr).trim();

  const months = {
    'stycznia': 0, 'lutego': 1, 'marca': 2, 'kwietnia': 3,
    'maja': 4, 'czerwca': 5, 'lipca': 6, 'sierpnia': 7,
    'września': 8, 'października': 9, 'listopada': 10, 'grudnia': 11
  };

  // "środa, kwietnia 1, 2026" lub "kwietnia 1, 2026"
  const polishMatch = s.match(/(stycznia|lutego|marca|kwietnia|maja|czerwca|lipca|sierpnia|września|października|listopada|grudnia)\s+(\d{1,2}),?\s+(\d{4})/i);
  if (polishMatch) {
    const [, monthName, day, year] = polishMatch;
    const date = new Date(Number(year), months[monthName.toLowerCase()], Number(day));
    return isNaN(date) ? null : date.getTime();
  }

  const m = s.match(/^(\d{1,2})[.\-/](\d{1,2})[.\-/](\d{2,4})$/);
  if (m) {
    let [, d, mo, y] = m;
    if (y.length === 2) y = '20' + y;
    const date = new Date(Number(y), Number(mo) - 1, Number(d));
    return isNaN(date) ? null : date.getTime();
  }

  return null;
}

// ==================== KONFIG ====================

const FIELD_ROWS = {
  data:        4,   // wiersz 5
  tytul:       5,   // wiersz 6
  typGrafiki:  6,   // wiersz 7
  typPosta:    7,   // wiersz 8
  linkGrafiki: 10,  // wiersz 11
  opis:        12,  // wiersz 13
  cta:         14,  // wiersz 15
  hasztagi:    16,  // wiersz 17
  status:      18,  // wiersz 19
  notatki:     20,  // wiersz 21
  feedback:    22,  // wiersz 23
  taskId:      24,  // wiersz 25
};

const START_COL = 1;

// ==================== LOGIKA ====================

const input = $input.first().json;

let rows = [];
if (Array.isArray(input)) rows = input[0]?.values || [];
else if (input.values) rows = input.values;
else if (input.valueRanges) rows = input.valueRanges[0]?.values || [];

if (!rows.length) {
  return [{ json: { error: 'Brak danych w arkuszu' } }];
}

const getCell = (rowIdx, colIdx) => {
  const row = rows[rowIdx];
  if (!row || colIdx >= row.length) return '';
  const val = row[colIdx];
  if (val === null || val === undefined) return '';
  return String(val).trim();
};

const maxCols = Math.max(0, ...rows.map(r => r?.length || 0));

const posts = [];
let currentDate = '';        // ostatnia widziana data
let currentDateTimestamp = null;
let currentDateColumn = null;

for (let col = START_COL; col < maxCols; col++) {
  // Aktualizuj datę jeśli w tej kolumnie jest nowa
  const dateInThisCol = getCell(FIELD_ROWS.data, col);
  if (dateInThisCol) {
    currentDate = dateInThisCol;
    currentDateTimestamp = parseDateToTimestamp(dateInThisCol);
    currentDateColumn = col;
  }

  // Zbierz pola dla tej kolumny
  const post = {};
  for (const [field, rowIdx] of Object.entries(FIELD_ROWS)) {
    post[field] = getCell(rowIdx, col);
  }

  // Post musi mieć tytuł LUB opis LUB link grafiki, żeby być realnym postem
  const isRealPost = post.tytul || post.opis || post.linkGrafiki;
  if (!isRealPost) continue;

  // Jeśli kolumna nie ma własnej daty — użyj ostatniej widzianej
  if (!post.data) post.data = currentDate;

  post.dueDate = post.data === currentDate
    ? currentDateTimestamp
    : parseDateToTimestamp(post.data);

  post.column = col;
  post.columnLetter = colIndexToLetter(col);
  post.dayStartColumn = currentDateColumn;

  posts.push(post);
}

// ==================== RETURN ====================

if (posts.length === 0) {
  return [{ json: { message: 'Brak postów', maxCols, rowsCount: rows.length } }];
}

return posts.map(post => ({ json: post }));

